// Get input data - handle both {payload: {...}} and flat structures
var input = items[0].json;
var payload = input.payload || input;

// Validate order_items
var orderItems = payload.order_items || [];
if (!Array.isArray(orderItems) || orderItems.length === 0) {
  throw new Error("order_items must be a non-empty array");
}

// Validate each item
for (var i = 0; i < orderItems.length; i++) {
  var item = orderItems[i];
  if (!item.name || !item.qty || item.price === undefined) {
    throw new Error("Invalid order item at index " + i + ": missing name, qty, or price");
  }
}

// Generate order ID
var now = new Date();
var date = now.toISOString().slice(0, 10).replace(/-/g, "");
var random = Math.floor(Math.random() * 900) + 100;
var orderId = "UDO-" + date + "-" + random;

// Build Square line items
var squareLineItems = [];
for (var j = 0; j < orderItems.length; j++) {
  var item = orderItems[j];
  squareLineItems.push({
    name: item.name,
    quantity: String(item.qty),
    base_price_money: {
      amount: Math.round(Number(item.price) * 100),
      currency: "USD"
    }
  });
}

// Build JSON for SQL
var orderItemsJson = JSON.stringify(orderItems);
var orderItemsSql = "'" + orderItemsJson.replace(/'/g, "''") + "'::jsonb";

return [{
  json: {
    order_id: orderId,
    customer_name: payload.customer_name || "",
    email: payload.email || "",
    phone: payload.phone || "",
    order_items_sql: orderItemsSql,
    subtotal: Number(payload.subtotal || 0),
    tax: Number(payload.tax || 0),
    total: Number(payload.total || 0),
    pickup_time: payload.pickup_time || "",
    special_instructions: payload.special_instructions || "",
    square_line_items_with_tax: squareLineItems,
    subtotal_cents: Math.round(Number(payload.subtotal || 0) * 100),
    tax_cents: Math.round(Number(payload.tax || 0) * 100)
  }
}];

const httpResponse = items[0].json;

// Debug: log what we received
console.log("HTTP Response keys:", Object.keys(httpResponse));
console.log("HTTP Response:", JSON.stringify(httpResponse, null, 2).substring(0, 500));

// Extract payment link data
let paymentUrl = "";
let paymentId = "";

if (httpResponse.payment_link) {
  paymentUrl = httpResponse.payment_link.url || "";
  paymentId = httpResponse.payment_link.id || "";
} else if (httpResponse.body && httpResponse.body.payment_link) {
  paymentUrl = httpResponse.body.payment_link.url || "";
  paymentId = httpResponse.body.payment_link.id || "";
}

const original = items[0].json;

// Get order items from original payload
let orderItems = [];
try {
  const payload = original.payload || original;
  if (payload.order_items) {
    orderItems = typeof payload.order_items === 'string' 
      ? JSON.parse(payload.order_items) 
      : payload.order_items;
  }
} catch(e) {
  orderItems = [];
}

return [{
  json: {
    payment_link_url: paymentUrl,
    payment_link_id: paymentId,
    email: original.email,
    customer_name: original.customer_name,
    order_id: original.order_id,
    phone: original.phone,
    pickup_time: original.pickup_time,
    special_instructions: original.special_instructions || "",
    order_items: orderItems,
    order_items_sql: original.order_items_sql,
    subtotal: original.subtotal,
    tax: original.tax,
    total: original.total
  }
}];

